var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"혹시 또 악몽을 꾼 거니?","JPN":"もしかしてまた悪夢を見たの？","ENG":"Are you having nightmares again?","TWN":"又做惡夢嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"그건 아니야? 다행이다…….","JPN":"それは違う？　よかった……","ENG":"No? That's a relief...","TWN":"不是嗎？那就好……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"으응? 무릎…… 멍 들었네.","JPN":"うん？　膝……あざができてるね。","ENG":"Hmm? There's... a bruise on my knee.","TWN":"嗯？膝蓋……瘀青咧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"네가 무서운 악몽이라도 꾼 걸까 봐 부딪히는 줄도 모르고 달려왔어.","JPN":"あなたが怖い悪夢でも見たんじゃないかと思って、ぶつかったのも知らずに走ってきたの。","ENG":"I was so worried that you were having a terrifying nightmare that I didn't notice I had bumped my knee.","TWN":"可能因為擔心你是做惡夢，急著跑來時不小心撞到的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"걱정할 줄 알았다면 조심할 걸.","JPN":"心配するって知ってたら気をつけたのに。","ENG":"I should've been more careful if I knew it would worry you...","TWN":"早知道你會擔心，我就小心點。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"이쯤은 괜찮아. 별일 아니야. 한밤 코- 자고 나면 금방 나아.","JPN":"このくらいは平気だよ。何でことない。一晩寝ればすぐ治るから。","ENG":"I'm okay. It's nothing. I'll be all better after a good night's sleep.","TWN":"小事啦，沒什麼，睡一覺起來就會消的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"Hu hu...","TWN":"……呵呵。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"아주 오랫동안 혼자 다녀서 그런가? 누군가 나를 걱정해 준다는 거, 익숙하지 않거든.","JPN":"とても長い間一人でいたからかな？　誰かが私を心配してくれるの、慣れてないよ。","ENG":"I'm not used to people being concerned about me. Maybe it's because I've been alone for so long.","TWN":"是因為我一直以來都是一個人嗎？我不太習慣有人關心我呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"간질간질하고 기분 좋네.","JPN":"くすぐったくて気持ちいいね。","ENG":"I feel good and all ticklish inside.","TWN":"但又覺得暖暖的，很開心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"악몽을 꾼 게 아니라면 난 무슨 일로 부른 거야?","JPN":"悪夢を見たわけじゃないなら、どうして私を呼んだの？","ENG":"If you didn't have a nightmare, why did you call me?","TWN":"既然你沒做惡夢，那找我來有什麼事？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"좋아.","JPN":"いいよ。","ENG":"Okay.","TWN":"我願意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"원래부터 너의 악몽은 언제나 내가 가져갈 생각이었으니까.","JPN":"最初からあなたの悪夢はいつも私が持っていくつもりだったから。","ENG":"I've always intended to take away your nightmares.","TWN":"我原本就打算總有一天要帶走你的惡夢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FULL","text":{"KOREA":"그리고 너의 목적이, 나의 사명과 맞닿아 있다는 건 이미 알고 있으니까.","JPN":"それに、あなたの目的が、私の使命と繋がっているということはすでに知ってたから。","ENG":"Also, I already know that your goal is in line with my mission.","TWN":"而且我知道你的目的和我的使命是相符的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};